var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"라이트닝──! 익스큐션──!!","JPN":"ライトニング───！　エクスキューージョン！！","ENG":"Lightning──! Execution──!!","TWN":"雷光──！處刑──！！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_ReinforcedB_NULL","text":{"KOREA":"근육 덩어리 녀석, 오랜만이라고 엄청 신났네.","JPN":"筋肉マン、久しぶりだからって浮かれちゃって。","ENG":"The musclehead's giddy just because it's been a while.","TWN":"肌肉男，好久不見，你還真興奮。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH"},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_ReinforcedB_NULL","text":{"KOREA":"저렇게 날뛰면 우리 있는 곳까지 문제 생기는 거 아니야?","JPN":"あんなに暴れたらこっちまでとばっちり食らうんじゃないの？","ENG":"If he ramps up like that, won't it cause trouble on our side too?","TWN":"你那樣蹦蹦跳跳，會不會連我們所在的地方也出問題？"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"무, 무슨 짓입니까, 실비아 씨!","JPN":"な、何ですか、シルビアさん！","ENG":"W-what are you doing, Sylvia?!","TWN":"妳、妳在幹什麼？希爾維亞！"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_ReinforcedB_NULL","text":{"KOREA":"답지 않게 뭘 움츠러들고 있어? 사령관이면 사령관답게 어깨 쫙 펴라고.","JPN":"何縮こまってるの？　らしくないわね。司令官なら司令官らしくシャンとしなさい。","ENG":"Why are you shrinking like that? Square your shoulders. You're the commander here.","TWN":"幹嘛縮成一團？真不像你，既然是司令官就要有司令官的風範，要抬頭挺胸。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"움츠러든 적 없습니다. 잠시 생각을 정리 중이었죠.","JPN":"縮こまってなんかいません。少し頭の中を整理していただけです。","ENG":"I wasn't shrinking. I was organizing my thoughts.","TWN":"我沒有畏縮過，只是暫時在整理思緒。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 실비아 씨처럼 즉흥적으로 행동하는 줄 아십니까?","JPN":"僕はシルビアさんのように衝動的な行動はしませんよ。","ENG":"Do you take me for someone who acts on impulse like you?","TWN":"妳以為我像妳一樣即興行動嗎？"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_ReinforcedB_NULL","text":{"KOREA":"예이, 예이. 어련하시겠어. 난 마저 승강기나 고치러 갈게.","JPN":"はいはい、そうですね。アタシは昇降機の修理に戻るわ。","ENG":"Yeah, yeah, sure. I'll get back to fixing the elevator.","TWN":"唉唷唉唷，你說得都對。我先去繼續修理電梯。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_ReinforcedB_NULL","text":{"KOREA":"호위는 부탁해, 카일.","JPN":"護衛よろしくね、カイル。","ENG":"Cover me, Kyle.","TWN":"護衛就拜託你了，凱爾。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"여기는 알파. 심부로 향할 수 있는 3번 승강기의 개수 작업을 시작했습니다.","JPN":"こちらアルファ。深部へ向かう3番昇降機の改修作業を始めました。","ENG":"Alpha here. Beginning repairs on elevator 3 for deep access.","TWN":"這裡是阿爾法，已經開始進行能前往深處的3號電梯修繕作業。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"본부. 작전조와의 통신이 원활한지 확인바랍니다.","JPN":"本部。作戦組との通信状態の確認をお願いします。","ENG":"HQ, confirm that comms with the ops team are stable.","TWN":"本部，請確認和作戰組的通訊是否暢通。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"양방향 통신은 시뮬레이션 결과보다 약 12% 우세한 성능을 보이고 있다.","JPN":"両方向通信はシミュレーション結果より約12％優秀な性能を見せている。","ENG":"Two-way comms are performing about 12% better than the simulation results.","TWN":"雙向通訊比模擬結果呈現約12%優勢的性能。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"이 또한 다-크 세븐의 활약 덕분이지.","JPN":"これもまたダーークセブンの活躍のおかげだ。","ENG":"Thanks to Da-rk Seven's contributions, of course.","TWN":"這又是多虧Dark 7的活躍表現。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"동료들의 희생에 묵념하겠다.","JPN":"仲間の犠牲に黙祷する。","ENG":"We will observe a moment of silence for our comrades' sacrifice.","TWN":"為同伴們的犧牲默哀。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령이 달고 간 소형 카메라의 송출도 문제없어.","JPN":"大佐がつけていった小型カメラの発信も問題なし。","ENG":"The feed from the Colonel's mini camera looks fine.","TWN":"上校帶著的小型攝影機輸出也沒有問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"번개가 번쩍거려서 눈은 아프지만, 심층 환경에 맞춰 선로전환기의 개량을 시작하지.","JPN":"雷のせいで目がチカチカするが、深層環境に合わせて線路転換器の改良を始めよう。","ENG":"The lightning flashes are hard on the eyes, but I'll begin adapting the Track Switcher for Deep Floor use.","TWN":"雖然閃電一閃一閃眼睛很痛，但要配合深層環境，開始進行線路轉換器的改良。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시간은 어느 정도로 예상하십니까?","JPN":"予想される所要時間は？","ENG":"What's the ETA?","TWN":"預計會花多久時間？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"부품은 마련했으니 오래 걸리는 작업은 아니야.","JPN":"部品は揃ってるし、そんなに長くはかからない。","ENG":"Parts are ready, so it shouldn't take long.","TWN":"零件已經準備好，作業時間不會太久。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다만… 지상의 CSE레벨이 올라가는 게 걸리는군.","JPN":"ただ……地上のCSEレベルが上がっているのが気になるな。","ENG":"But... the surface CSE level ticking up is concerning.","TWN":"但是…地面的CSE等級上升需要時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"여섯 도시의 대균열에서 일제히 이상 현상이 관측되었으니, 이후부터는 최악을 가정해야 합니다.","JPN":"6つの都市の大亀裂から一斉に異常現象が観測されましたし、これからは最悪を想定する必要があります。","ENG":"With simultaneous anomalies across the six city's Grand Dimension Crevices, we proceed assuming the worst.","TWN":"六座城市的大峽谷同時觀測到異常現象，之後必須假設最糟的情況。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"본부는 브라보 팀을 통해 지상의 움직임도 면밀히 살펴주시길.","JPN":"本部はブラボーチームを通して、地上の動向も細かく確認してください。","ENG":"HQ, monitor topside closely through Team Bravo.","TWN":"請本部透過布拉伯組，密切關注地面動向。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병 나부랭이한테 요구가 많군, 소령.","JPN":"一介の傭兵に要求が多いな、少佐。","ENG":"Lotta asks for a mere merc, Major.","TWN":"你對小傭兵要求還真多，少校。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"보수금은 이자까지 쳐서 두둑이 받아야 하니, 거기서 죽지 말고 돌아오기나 해.","JPN":"報酬は利息も含めて弾んでもらうから、生きて帰って来いよ。","ENG":"Just make it back alive. The hazard pay with interest won't claim itself.","TWN":"報酬要加上利息，我要收一筆豐厚的費用，別死在那裡，要回來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"두말할 것도 없습니다. 책임완수는 군인의 본분이자 역할이니까요.","JPN":"当然です。責任を果たすのが軍人の役目ですから。","ENG":"No need to say it twice. Fulfilling duty is a soldier's duty and honor.","TWN":"不必多說，履行責任是軍人的本分也是職責。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그럼, 임무 진척 후 재송신하겠습니다.","JPN":"では、任務の遂行後にまた。","ENG":"We'll report again once we've progressed.","TWN":"那就等任務進行後再重新發送。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"해당 굉음은 관리국 규정 상 소음으로 구분됩니다.","JPN":"この轟音は管理局の規定上、騒音に分類されます。","ENG":"That booming qualifies as noise under Administration regulations.","TWN":"該轟鳴聲依據管理局規定分類為噪音。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨의 임무능률을 위해, 큰 소리로 떠드는 건 자제해주시길.","JPN":"シルビアさんの任務能率のために、大声でのおしゃべりは控えていただきたい。","ENG":"For Sylvia's work efficiency, please refrain from loud talking.","TWN":"為了希爾維亞的任務效率，請不要大聲喧嘩。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"교전 수칙, 상정 완료.","JPN":"交戦規定、想定完了。","ENG":"Engagement protocol assumptions locked.","TWN":"交戰守則，提交完畢。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"임무에 따라 적을 섬멸한다.","JPN":"任務に従い、敵を殲滅する。","ENG":"Eliminate the enemy as per the mission.","TWN":"按照任務殲滅敵人。"},"stage":{"bg":"GAME_LIFT2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};